<script>
import { Carousel3d, Slide } from "vue-carousel-3d";
import { mapActions, mapState } from "vuex";
import MovieItem from "@/components/Movie/MovieItemC";
import axios from "axios";
export default {
  data: () => ({
    upcoming: [],
    toprated: [],
    latest: [],
    imageTransition: true,
    search: "",
    attrs: {
      class: "mb-6",
      boilerplate: false,
      elevation: 2,
    },
    page: 1,
    firstLoad: true,
    apiKey: "194d8a67379374e13e12c99420c19098",
    items: [
      {
        icon: "mdi-movie-roll",
        title: "Movies",
        route: "/movies",
      },
      {
        icon: "mdi-film",
        title: "Serials",
      },
      {
        icon: "mdi-television",
        title: "Tv",
      },
      {
        icon: "mdi-controller-classic-outline",
        title: "Games",
      },
      {
        icon: "mdi-cog",
        title: "Programs",
      },
      {
        icon: "mdi-camera",
        title: "Others",
      },
    ],
  }),
  components: {
    Carousel3d,
    Slide,
    MovieItem,
  },
  computed: {
    ...mapState({
      S_dialog: (store) => store.movie.S_dialog,
    }),
  },
  methods: {
    ...mapActions([
      "A_searchResult",
      "A_changeSkeletonLoading",
      "A_enableDialog",
    ]),
    async getUpComingMovies() {
      await axios
        .get(
          `https://api.themoviedb.org/3/movie/upcoming?api_key=${this.apiKey}&language=en-US&page=1`
        )
        .then((resp) => {
          // console.log(resp.data);
          this.upcoming = resp.data.results;
        });
    },
    async fetchSearch(searcharg) {
      if (this.search != "") {
        await axios
          .get(
            `https://api.themoviedb.org/3/search/movie?query=${searcharg}&api_key=${this.apiKey}`
          )
          .then((resp) => {
            // console.log(resp);
            this.searchList = resp.data.results;
            this.A_searchResult(resp.data.results);
          });
      }
    },
    searchResult() {
      if (this.search != "") {
        if (this.$route.name === "moviedetail") {
          // console.log("yes");
          // this.$router.push({ params: { id: this.search } });
          // if (document.readyState == "complete") {
          //   console.log("completed");
          // } else {
          //   console.log("not yet");
          // }
          this.A_changeSkeletonLoading(true);
          setTimeout(() => {
            this.A_changeSkeletonLoading(false);
          }, 2000);
        } else {
          this.A_changeSkeletonLoading(true);
          this.A_enableDialog(true);
          setTimeout(() => {
            this.A_enableDialog(false);
            this.A_changeSkeletonLoading(false);
          }, 2000);
          this.$router.push({
            name: "moviedetail",
            params: { id: this.search },
          });
        }
        localStorage.setItem("searchKey", this.search);
      }
      // this.search = "";
      window.scrollTo({
        behavior: "smooth",
        top: 0,
      });
    },
    async getTopRatedMovies() {
      await axios
        .get(
          `https://api.themoviedb.org/3/movie/top_rated?api_key=${this.apiKey}&language=en-US&page=1`
        )
        .then((resp) => {
          // console.log(resp);
          this.toprated = resp.data.results;
        });
    },
    async getLatestMovies() {
      await axios
        .get(
          `https://api.themoviedb.org/3/movie/latest?api_key=${this.apiKey}&language=en-US&page=1`
        )
        .then((resp) => {
          // console.log(resp);
          // console.log(
          //   `https://api.themoviedb.org/3/movie/latest?api_key=${this.apiKey}&language=en-US&page=1`
          // );
          this.latest = resp.data;
        });
    },
    imageAnimation() {
      this.imageTransition = true;
      setTimeout(() => {
        this.imageTransition = false;
        this.$refs.search_button.focus();
      }, 1500);
    },
  },
  mounted() {
    this.getUpComingMovies();
    this.getTopRatedMovies();
    this.imageAnimation();
  },
  created() {
    const readyHandler = () => {
      if (document.readyState == "complete") {
        setTimeout(() => {
          this.firstLoad = false;
        }, 1500);
        document.removeEventListener("readystatechange", readyHandler);
      }
    };
    document.addEventListener("readystatechange", readyHandler);
    readyHandler();
  },
};
</script>

