    async fetchSearch(searcharg) {
      if (this.search != "") {
        await axios
          .get(
            `https://api.themoviedb.org/3/search/movie?query=${searcharg}&api_key=${this.apiKey}`
          )
          .then((resp) => {
            this.searchList = resp.data.results;
            this.A_searchResult(resp.data.results);
            // console.log(this.searchList);
          });
        this.search = "";
      }
    },
    querySelections(v) {
      // console.log(this.searchList);
      this.loading = true;
      // console.log(this.items);
      // Simulated ajax query
      setTimeout(() => {
        this.items = this.getList.filter((e) => {
          return (e || "").toLowerCase().indexOf((v || "").toLowerCase()) > -1;
        });
        this.loading = false;
      }, 500);
    },
    increaseSize() {
      let searchButton = document.querySelector(".search");
      searchButton.classList.add("increase_search_size");
    },
    shrinkSize() {
      let searchButton = document.querySelector(".search");
