        if (this.$route.name === "moviedetail") {
          this.A_changeSkeletonLoading(true);
          this.A_enableDialog(true);
          setTimeout(() => {
            this.A_changeSkeletonLoading(false);
            this.A_enableDialog(false);
            window.scrollTo({
