      return this.$route.name == "home";
    },
    ...mapState({
      S_searchResult: (store) => store.movie.S_searchResult,
    }),
    getList() {
      let sol = this.searchList.map((el) => {
        // console.log("as", el.original_title);
        return el.original_title;
      });
      // console.log("as", sol);
      return sol;
    },
    getImage() {
      let sol = this.searchList.map((el) => {
        // console.log("as", el.original_title);
        return el.poster_path;
      });
      // console.log("as", sol);
      return sol;
    },
    barScroll() {
      return window.scrollY == 0;
    },
  },
  created() {
    const readyHandler = () => {
      if (document.readyState == "complete") {
        setTimeout(() => {
          this.firstLoad = false;
        }, 1500);
        document.removeEventListener("readystatechange", readyHandler);
      }
    };
    document.addEventListener("readystatechange", readyHandler);
    readyHandler();
    // console.log(this.S_skeletonLoading);
