<template>
  <v-app>
    <NavBar v-if="false" />
    <MovieNavBar v-if="true" />
    <Notification v-if="false" />
    <v-main>
      <v-dialog v-model="S_dialog" max-width="400" hide-overlay>
        <v-card>
          <v-progress-linear color="#3d4b5e" indeterminate></v-progress-linear>
        </v-card>
      </v-dialog>
      <!--  -->
      <!-- <router-view /> -->
      <router-view v-slot="{ Component }">
        <transition name="fade">
          <component :is="Component" />
        </transition>
      </router-view>
      <!--  -->
      <v-slide-y-transition>
        <div class="scroll_to_top" v-if="scrollButton">
          <v-btn fab color="#3d4b5e" @click="scrollToTop">
            <v-icon color="white">mdi-chevron-up</v-icon>
          </v-btn>
        </div>
      </v-slide-y-transition>
    </v-main>
    <Footer v-if="false" />
    <FooterMovie v-if="true" />
  </v-app>
</template>

<script>
import Notification from "@/components/Cart/NotificationList.vue";
import NavBar from "@/components/ecommerceTwo/NavBar/NavBarC";
import Footer from "@/components/ecommerceTwo/NavBar/FooterC";
import MovieNavBar from "@/components/Movie/NavBarC";
import FooterMovie from "@/components/Movie/FooterC";
// eslint-disable-next-line no-unused-vars
import { mapActions, mapState } from "vuex";
export default {
  name: "App",

  data: () => ({
    //
    dialog: true,
    scrollButton: false,
  }),
  methods: {
    ...mapActions(["A_enableDialog"]),
    scrollToTop() {
      window.scrollTo({
        behavior: "smooth",
        top: 0,
      });
    },
  },
  mounted() {
    // console.log("mounted");
    this.A_enableDialog(true);
    setTimeout(() => {
      this.A_enableDialog(false);
    }, 1500);
    // let scrollBtn = document.querySelector(".scroll_to_top");
    scrollY > 200
      ? [(this.scrollButton = true)]
      : [(this.scrollButton = false)];

    window.onscroll = () => {
      scrollY > 200
        ? [(this.scrollButton = true)]
        : [(this.scrollButton = false)];
    };
  },
  computed: {
    ...mapState({
      S_dialog: (store) => store.movie.S_dialog,
    }),
  },
  components: {
    NavBar,
    MovieNavBar,
    Footer,
    FooterMovie,
    Notification,
  },
};
</script>

